#include <stdio.h>
#include <stdlib.h>

typedef struct {int x; int dA; int dB;} Event;
int cmp(const void *a, const void *b){
    return ((Event*)a)->x - ((Event*)b)->x;
}
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,M; scanf("%d %d", &N, &M);
        int total = N+M;
        Event *ev = (Event*)malloc(sizeof(Event)*(2*total));
        int idx=0;
        for(int i=0;i<N;i++){
            int L,R; scanf("%d %d", &L, &R);
            ev[idx++] = (Event){L, 1, 0};
            ev[idx++] = (Event){R, -1, 0};
        }
        for(int i=0;i<M;i++){
            int L,R; scanf("%d %d", &L, &R);
            ev[idx++] = (Event){L, 0, 1};
            ev[idx++] = (Event){R, 0, -1};
        }
        qsort(ev, idx, sizeof(Event), cmp);
        long long ans=0;
        long long cntA=0, cntB=0;
        int prev = ev[0].x;
        for(int i=0;i<idx;i++){
            int cur = ev[i].x;
            if(cur>prev && cntA && cntB) ans += (long long)(cur-prev)*cntA*cntB;
            cntA += ev[i].dA;
            cntB += ev[i].dB;
            prev = cur;
        }
        printf("%lld\n", ans);
        free(ev);
    }
    return 0;
}

