import java.io.*;
import java.util.*;
public class Main {
    static class Event {
        int x, dA, dB;
        Event(int x, int dA, int dB){this.x=x; this.dA=dA; this.dB=dB;}
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while(T-- > 0){
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int M = Integer.parseInt(st.nextToken());
            List<Event> ev = new ArrayList<>(2*(N+M));
            for(int i=0;i<N;i++){
                st = new StringTokenizer(br.readLine());
                int L = Integer.parseInt(st.nextToken());
                int R = Integer.parseInt(st.nextToken());
                ev.add(new Event(L,1,0));
                ev.add(new Event(R,-1,0));
            }
            for(int i=0;i<M;i++){
                st = new StringTokenizer(br.readLine());
                int L = Integer.parseInt(st.nextToken());
                int R = Integer.parseInt(st.nextToken());
                ev.add(new Event(L,0,1));
                ev.add(new Event(R,0,-1));
            }
            ev.sort(Comparator.comparingInt(e->e.x));
            long ans=0, cntA=0, cntB=0;
            int prev = ev.get(0).x;
            for(Event e: ev){
                if(e.x>prev && cntA>0 && cntB>0) ans += (long)(e.x-prev)*cntA*cntB;
                cntA += e.dA; cntB += e.dB; prev = e.x;
            }
            out.append(ans).append('\n');
        }
        System.out.print(out.toString());
    }
}

