const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = data[idx++];
let output = [];
for (let t = 0; t < T; t++) {
  const N = data[idx++];
  const M = data[idx++];
  let events = [];
  for (let i = 0; i < N; i++) {
    const L = data[idx++];
    const R = data[idx++];
    events.push([L, 1, 0]);
    events.push([R, -1, 0]);
  }
  for (let i = 0; i < M; i++) {
    const L = data[idx++];
    const R = data[idx++];
    events.push([L, 0, 1]);
    events.push([R, 0, -1]);
  }
  events.sort((a, b) => a[0] - b[0]);
  let cntA = 0, cntB = 0;
  let prev = events[0][0];
  let ans = 0n;
  for (const [x, dA, dB] of events) {
    if (x > prev && cntA && cntB) {
      ans += BigInt(x - prev) * BigInt(cntA) * BigInt(cntB);
    }
    cntA += dA;
    cntB += dB;
    prev = x;
  }
  output.push(ans.toString());
}
